using UnityEngine;

/// <summary>
/// Configuração de um projéctil (Enemy Creator — Etapa 2.2). Um EnemyAttack de
/// projéctil (Attack_ProjectileStraight/Arc/Homing, Attack_SpawnEnemyOrProjectile
/// — Etapa 2.1) referencia um asset ProjectileData e chama
/// <see cref="EnemyAttackController.SpawnProjectile"/>, que instancia
/// <see cref="ProjectileController"/> configurado a partir destes dados.
///
/// O mesmo asset pode ser partilhado por vários inimigos/ataques (ex: "Bala de
/// Drone Padrão" usada por várias Torretas).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Enemy/Projectile Data", fileName = "NewProjectileData")]
public class ProjectileData : ScriptableObject
{
    [Header("Identidade")]
    public string projectileId;
    public string displayName;

    [Header("Visual")]
    [Tooltip("Prefab customizado (opcional). Se vazio, ProjectileController cria um GameObject simples com Sprite + Rigidbody2D + CircleCollider2D (trigger).")]
    public GameObject prefab;

    [Tooltip("Usado apenas se 'prefab' estiver vazio.")]
    public Sprite sprite;

    [Header("Movimento — Laser ou Físico?")]
    [Tooltip("Se activo, o projéctil é um raio instantâneo (Raycast, alcance 'laserRange') em vez de um objecto físico que se desloca. Os campos de Movimento abaixo são ignorados.")]
    public bool isLaser = false;

    [Tooltip("Alcance do raio, se 'isLaser'.")]
    public float laserRange = 10f;

    [Tooltip("Velocidade do projéctil físico (m/s). Ignorado se 'isLaser'.")]
    public float speed = 6f;

    [Tooltip("GravityScale do Rigidbody2D. 0 = trajectória recta (\"físico\" sem queda). >0 = arco (cai com a gravidade) — usado por Attack_ProjectileArc.")]
    public float gravityScale = 0f;

    [Tooltip("Tempo de vida (segundos) antes de se autodestruir, caso não acerte em nada.")]
    public float lifetime = 5f;

    [Header("Quantidade / Frequência de Tiros")]
    [Tooltip("Quantidade de tiros (volleys) disparados por uso do ataque.")]
    [Min(1)] public int shotCount = 1;

    [Tooltip("Intervalo entre tiros consecutivos, em segundos. Só relevante se 'shotCount' > 1.")]
    public float fireInterval = 0.1f;

    [Header("Direcções (Disparo em Leque)")]
    [Tooltip("Ângulos adicionais (graus, relativos à direcção de disparo) — cada um dispara um projéctil extra por tiro. A direcção base (0°) é sempre incluída. Ex: [-15, 15] = 3 projécteis por tiro.")]
    public float[] extraAngles = new float[0];

    [Header("Segue o Player?")]
    [Tooltip("Se activo, o projéctil curva ligeiramente em direcção ao player durante o voo (ignorado se 'isLaser').")]
    public bool tracksPlayer = false;

    [Tooltip("Intensidade da perseguição: 0 = sem curva (recto), 1 = vira-se quase instantaneamente para o alvo. Valores baixos dão curvas 'leves' (projéctil teleguiado leve).")]
    [Range(0f, 1f)] public float trackingIntensity = 0.2f;

    [Header("Dano")]
    [Tooltip("Dano causado ao player ao acertar (PlayerProgress.Damage).")]
    public int damage = 1;

    [Tooltip("Força de empurrão aplicada ao player ao ser atingido.")]
    public float knockbackForce = 0f;

    [Header("Explode ao Colidir?")]
    public bool explodesOnImpact = false;
    public float explosionRadius = 1.5f;
    public int explosionDamage = 1;

    [Header("Interacção com o Mundo")]
    [Tooltip("Fere outros inimigos (EnemyHealth) que não sejam quem disparou.")]
    public bool canHurtOtherEnemies = false;

    [Tooltip("Pode destruir objectos com IProjectileDestructible (ex: pedras/blocos — Etapa 6+).")]
    public bool canDestroyObjects = false;

    [Tooltip("Pode activar switches/botões com IProjectileActivatable (ex: alvos de tiro — Etapa 6.1+).")]
    public bool canActivateSwitches = false;

    [Tooltip("Pode ser reflectido por objectos com IProjectileReflector (ex: escudos/espelhos).")]
    public bool canBeReflected = false;

    [Header("Carregamento (Telegraph)")]
    [Tooltip("Tempo de carregamento antes do disparo efectivo. Durante este tempo é instanciado 'chargeVfxPrefab' (destruído ao disparar) e tocado 'chargeSound'.")]
    public float chargeTime = 0f;

    public GameObject chargeVfxPrefab;
    public AudioClip chargeSound;

    [Header("Sons")]
    [Tooltip("Tocado no instante do disparo (ou de cada volley, se 'shotCount' > 1).")]
    public AudioClip fireSound;

    [Tooltip("Tocado ao acertar/colidir.")]
    public AudioClip impactSound;
}
